import { FaStar, FaCheck } from 'react-icons/fa';
import PropTypes from 'prop-types';
import { GiSparkles } from 'react-icons/gi';
import { getPackageIcon } from './useCoinStore';
import { useTranslation } from 'react-i18next';
import { STORE_PURCHASES_ENABLED } from '../../constants/featureFlags';

// -- dynamic style helpers (pass 2) --

const S = {
    border: { width: '20px', height: '20px', border: '3px solid rgba(255, 255, 255, 0.3)', borderTop: '3px solid white', borderRadius: '50%', animation: 'spin 1s linear infinite' },
    txt2: { fontSize: '32px', fontWeight: 'bold', color: 'white', textShadow: '0 2px 12px rgba(0, 0, 0, 0.4)' },
    txt: { fontSize: '13px', color: '#b5bac1', marginTop: '6px' },
    flex2: { fontSize: '16px', color: '#23a559', fontWeight: '600', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '6px', marginTop: '8px', textShadow: '0 0 10px rgba(87, 242, 135, 0.3)' },
    bg: { fontSize: '42px', fontWeight: 'bold', background: 'linear-gradient(135deg, #ffd700 0%, #ffed4e 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', textShadow: '0 0 30px rgba(255, 215, 0, 0.3)', marginBottom: '8px' },
    rel: { fontSize: '24px', fontWeight: 'bold', color: 'white', textAlign: 'center', marginBottom: '16px', textShadow: '0 2px 8px rgba(0, 0, 0, 0.3)', position: 'relative', zIndex: 1 },
    flex: { position: 'absolute', top: '-12px', left: '50%', transform: 'translateX(-50%)', background: 'linear-gradient(135deg, #5865f2 0%, #4752c4 100%)', color: 'white', fontSize: '12px', fontWeight: 'bold', padding: '6px 16px', borderRadius: '20px', display: 'flex', alignItems: 'center', gap: '6px', boxShadow: '0 4px 12px rgba(88, 101, 242, 0.4)', border: '1px solid rgba(255, 255, 255, 0.2)', animation: 'pulse 2s ease-in-out infinite' },
    abs: { position: 'absolute', top: '-50%', left: '-50%', width: '200%', height: '200%', background: 'radial-gradient(circle, rgba(88, 101, 242, 0.1) 0%, transparent 70%)', animation: 'rotate 8s linear infinite', pointerEvents: 'none' },
};


const card = (isPopular) => ({
    position: 'relative',
    background: isPopular
        ? 'linear-gradient(135deg, rgba(88, 101, 242, 0.15) 0%, rgba(88, 101, 242, 0.05) 100%)'
        : 'linear-gradient(135deg, rgba(255, 255, 255, 0.05) 0%, rgba(255, 255, 255, 0.02) 100%)',
    borderRadius: '20px',
    padding: '28px',
    border: isPopular ? '2px solid rgba(88, 101, 242, 0.5)' : '2px solid rgba(255, 255, 255, 0.1)',
    transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
    cursor: 'pointer',
    boxShadow: isPopular
        ? '0 8px 32px rgba(88, 101, 242, 0.3), inset 0 0 60px rgba(88, 101, 242, 0.1)'
        : '0 4px 20px rgba(0, 0, 0, 0.3)',
    transform: 'translateY(0)',
    overflow: 'hidden'
});

const hoverShadow = (isPopular, enter) => isPopular
    ? enter ? '0 12px 48px rgba(88, 101, 242, 0.4), inset 0 0 80px rgba(88, 101, 242, 0.15)' : '0 8px 32px rgba(88, 101, 242, 0.3), inset 0 0 60px rgba(88, 101, 242, 0.1)'
    : enter ? '0 8px 32px rgba(255, 215, 0, 0.2)' : '0 4px 20px rgba(0, 0, 0, 0.3)';

const hoverBorder = (isPopular, enter) => isPopular
    ? `2px solid rgba(88, 101, 242, ${enter ? 0.8 : 0.5})`
    : `2px solid ${enter ? 'rgba(255, 215, 0, 0.3)' : 'rgba(255, 255, 255, 0.1)'}`;

const buyBtn = (isPopular, loading) => ({
    width: '100%', padding: '16px', borderRadius: '12px', fontWeight: 'bold', fontSize: '16px', color: 'white',
    background: isPopular ? 'linear-gradient(135deg, #5865f2 0%, #4752c4 100%)' : 'linear-gradient(135deg, #23a559 0%, #3ba55d 100%)',
    border: 'none', cursor: loading ? 'not-allowed' : 'pointer', transition: 'all 0.3s',
    display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px',
    boxShadow: isPopular ? '0 6px 20px rgba(88, 101, 242, 0.4)' : '0 6px 20px rgba(87, 242, 135, 0.3)',
    opacity: loading ? 0.6 : 1, position: 'relative', zIndex: 1, overflow: 'hidden'
});

const btnShadow = (isPopular, enter) => isPopular
    ? `0 ${enter ? 8 : 6}px ${enter ? 28 : 20}px rgba(88, 101, 242, ${enter ? 0.6 : 0.4})`
    : `0 ${enter ? 8 : 6}px ${enter ? 28 : 20}px rgba(87, 242, 135, ${enter ? 0.5 : 0.3})`;

const _st1134 = {};

const PackageCard = ({ pkg, loading, selectedPackage, onPurchase }) => {
    const { t } = useTranslation();

    const Icon = getPackageIcon(pkg.icon);
    const totalCoins = pkg.coins + (pkg.bonus || 0);
    const isPopular = pkg.popular;
    const isLoading = loading && selectedPackage === pkg.id;
    const iconWrapperStyle = { display: 'flex', justifyContent: 'center', marginBottom: '20px', marginTop: isPopular ? '12px' : '0', position: 'relative', zIndex: 1 };
    const iconCircleStyle = {
        width: '100px', height: '100px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center',
        background: isPopular ? 'linear-gradient(135deg, rgba(88, 101, 242, 0.3) 0%, rgba(88, 101, 242, 0.1) 100%)' : 'linear-gradient(135deg, rgba(255, 215, 0, 0.2) 0%, rgba(255, 215, 0, 0.05) 100%)',
        boxShadow: isPopular ? '0 0 40px rgba(88, 101, 242, 0.3), inset 0 0 20px rgba(88, 101, 242, 0.2)' : '0 0 30px rgba(255, 215, 0, 0.2), inset 0 0 20px rgba(255, 215, 0, 0.1)',
        border: `2px solid ${isPopular ? 'rgba(88, 101, 242, 0.3)' : 'rgba(255, 215, 0, 0.2)'}`
    };
    const iconStyle = { fontSize: '48px', color: isPopular ? '#5865f2' : '#ffd700', filter: `drop-shadow(0 0 15px ${isPopular ? 'rgba(88, 101, 242, 0.5)' : 'rgba(255, 215, 0, 0.5)'})` };

    return (
        <div aria-label="package card"
            style={card(isPopular)}
            onMouseEnter={(e) => { e.currentTarget.style.transform = 'translateY(-8px)'; e.currentTarget.style.boxShadow = hoverShadow(isPopular, true); e.currentTarget.style.border = hoverBorder(isPopular, true); }}
            onMouseLeave={(e) => { e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = hoverShadow(isPopular, false); e.currentTarget.style.border = hoverBorder(isPopular, false); }}>
            {isPopular && <div style={S.abs} />}
            {isPopular && (
                <div style={S.flex}>
                    <FaStar className="fs-12" /> EN POP├£LER
                </div>
            )
            }

            {/* Icon */}
            <div style={iconWrapperStyle}>
                <div style={iconCircleStyle}>
                    <Icon style={iconStyle} />
                </div>
            </div>

            {/* Name */}
            <h3 style={S.rel}>{pkg.name}</ h3>

            {/* Coins */}
            <div className="center-mb20-z1">
                <div style={S.bg}>
                    {pkg.coins.toLocaleString()}
                </div>
                {pkg.bonus && (
                    <>
                        <div style={S.flex2}>
                            <GiSparkles className="fs-18" /> +{pkg.bonus.toLocaleString()} Bonus!
                        </div>
                        <div style={S.txt}>Toplam: {totalCoins.toLocaleString()} coin</div>
                    </>
                )}
            </div>

            {/* Price */}
            <div className="center-mb20-z1" >
                <div style={S.txt2}>
                    {pkg.price.toFixed(2)} {pkg.currency}
                </ div>
            </div>

            {/* Buy */}
            {
                STORE_PURCHASES_ENABLED ? (
                    <button
                        onClick={() => onPurchase(pkg)}
                        disabled={loading}
                        style={buyBtn(isPopular, loading)}
                        onMouseEnter={(e) => { if (!loading) { e.target.style.transform = 'translateY(-2px)'; e.target.style.boxShadow = btnShadow(isPopular, true); } }}
                        onMouseLeave={(e) => { e.target.style.transform = 'translateY(0)'; e.target.style.boxShadow = btnShadow(isPopular, false); }}>
                        {isLoading ? (
                            <><div style={S.border} />{t('processing')}</>
                        ) : (
                            <><FaCheck className="fs-18" />{t('purchase')}</>
                        )}
                    </button>
                ) : (
                    <button disabled style={_st1134}>
                        ≡ƒöÆ {t('coming_soon', 'Coming Soon')}
                    </button>
                )
            }
        </div>
    );
};

PackageCard.propTypes = {
    pkg: PropTypes.object,
    loading: PropTypes.func,
    selectedPackage: PropTypes.bool,
    onPurchase: PropTypes.func,
};
export default PackageCard;

export const styles = {
  overlay: {
    position: 'fixed',
    inset: 0,
    background: 'rgba(0, 0, 0, 0.85)',
    backdropFilter: 'blur(8px)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    zIndex: 9999,
    padding: '20px',
    animation: 'fadeIn 0.2s ease-in'
  },
  modal: {
    background: 'linear-gradient(135deg, #2a2d35 0%, #1e2024 100%)',
    borderRadius: '24px',
    maxWidth: '1000px',
    width: '100%',
    maxHeight: '90vh',
    overflowY: 'auto',
    boxShadow: '0 20px 60px rgba(0, 0, 0, 0.5), 0 0 100px rgba(255, 215, 0, 0.1)',
    border: '1px solid rgba(255, 215, 0, 0.2)',
    animation: 'slideUp 0.3s ease-out'
  },
  header: {
    position: 'sticky',
    top: 0,
    background: 'linear-gradient(135deg, #2a2d35 0%, #1e2024 100%)',
    borderBottom: '2px solid rgba(255, 215, 0, 0.15)',
    padding: '24px 32px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    zIndex: 10,
    borderRadius: '24px 24px 0 0'
  },
  headerTitle: {
    fontSize: '32px',
    fontWeight: 'bold',
    background: 'linear-gradient(135deg, #ffd700 0%, #ffed4e 100%)',
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
    display: 'flex',
    alignItems: 'center',
    gap: '12px',
    marginBottom: '8px'
  },
  coinIcon: { fontSize: '36px', color: '#ffd700', filter: 'drop-shadow(0 0 10px rgba(255, 215, 0, 0.5))' },
  balanceText: { fontSize: '14px', color: '#b5bac1', marginTop: '4px' },
  balanceAmount: { color: '#ffd700', fontWeight: 'bold', fontSize: '16px', textShadow: '0 0 10px rgba(255, 215, 0, 0.3)' },
  closeBtn: {
    color: '#b5bac1',
    background: 'rgba(255, 255, 255, 0.05)',
    border: '1px solid rgba(255, 255, 255, 0.1)',
    borderRadius: '12px',
    padding: '12px',
    cursor: 'pointer',
    transition: 'all 0.2s',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center'
  },
  packagesGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
    gap: '24px'
  },
  infoBox: {
    marginTop: '32px',
    padding: '24px',
    background: 'linear-gradient(135deg, rgba(255, 255, 255, 0.05) 0%, rgba(255, 255, 255, 0.02) 100%)',
    borderRadius: '16px',
    border: '1px solid rgba(255, 255, 255, 0.1)',
    boxShadow: '0 4px 20px rgba(0, 0, 0, 0.2)'
  },
  infoList: { fontSize: '14px', color: '#dbdee1', display: 'flex', flexDirection: 'column', gap: '12px' },
  infoItem: { display: 'flex', alignItems: 'flex-start', gap: '10px' }
};

export const ANIMATIONS_CSS = `
  @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
  @keyframes slideUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
  @keyframes pulse { 0%, 100% { transform: translateX(-50%) scale(1); } 50% { transform: translateX(-50%) scale(1.05); } }
  @keyframes spin { to { transform: rotate(360deg); } }
  @keyframes rotate { to { transform: rotate(360deg); } }
`;

export const INFO_ITEMS = [
  { icon: 'Γ£ô', color: '#23a559', textKey: 'store.info.instant' },
  { icon: 'Γ£ô', color: '#23a559', textKey: 'store.info.secure' },
  { icon: 'Γ£ô', color: '#23a559', textKey: 'store.info.bonus' },
  { icon: 'ΓÜá', color: '#f0b232', textKey: 'store.info.testMode', small: true }
];

import { useState, useEffect } from 'react';
import { FaCoins, FaStar, FaCrown } from 'react-icons/fa';
import { GiSparkles } from 'react-icons/gi';
import toast from '../../utils/toast';
import { getApiBase } from '../../utils/apiEndpoints';
import logger from '../../utils/logger';

const ICON_MAP = { '≡ƒÆ░': FaCoins, '≡ƒÆÄ': GiSparkles, '≡ƒææ': FaCrown, '≡ƒîƒ': FaStar };

export const getPackageIcon = (icon) => ICON_MAP[icon] || FaCoins;

export default function useCoinStore(onPurchaseComplete, onClose) {
    const [packages, setPackages] = useState([]);
    const [loading, setLoading] = useState(false);
    const [selectedPackage, setSelectedPackage] = useState(null);

    const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || getApiBase();
    const token = localStorage.getItem('access_token');

    useEffect(() => {
        (async () => {
            try {
                const res = await fetch(`${API_BASE_URL}/coins/packages/`);
                const data = await res.json();
                if (data.success) setPackages(data.packages);
            } catch (err) {
                logger.error('Γ¥î Coin packages could not be loaded:', err);
            }
        })();
    }, []);

    const handlePurchase = async (pkg) => {
        setSelectedPackage(pkg.id);
        setLoading(true);
        try {
            const res = await fetch(`${API_BASE_URL}/coins/checkout/`, {
                method: 'POST',
                headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
                body: JSON.stringify({ package_id: pkg.id, payment_method: 'stripe' })
            });
            const data = await res.json();
            if (data.success) {
                if (data.test_mode) {
                    toast.success(`Γ£à ${pkg.coins + (pkg.bonus || 0)} coin added!\n\nYeni bakiye: ${data.new_balance} coin`, { duration: 4000 });
                    if (onPurchaseComplete) onPurchaseComplete(data.new_balance);
                    onClose();
                } else {
                    window.location.href = data.checkout_url;
                }
            }
        } catch (err) {
            logger.error('Γ¥î Purchase error:', err);
            toast.error('Purchase failed. Please try again.');
        } finally {
            setLoading(false);
            setSelectedPackage(null);
        }
    };

    return { packages, loading, selectedPackage, handlePurchase };
}

