import React, { useState } from 'react';
import PropTypes from 'prop-types';
import { FaTimes, FaCoins, FaShoppingBag, FaTshirt, FaBitcoin } from 'react-icons/fa';
import { useTranslation } from 'react-i18next';
import useCryptoStore from '../CryptoStoreModal/useCryptoStore';
import StoreTab from '../CryptoStoreModal/StoreTab';
import InventoryTab from '../CryptoStoreModal/InventoryTab';
import DepositTab from '../CryptoStoreModal/DepositTab';
import styles from '../CryptoStoreModal/cryptoStoreStyles';
import useModalA11y from '../../hooks/useModalA11y';

const S = {
    txt4: { color: '#ff5d5d' },
    txt3: { marginLeft: 8, color: '#b5bac1' },
    bg: { padding: '10px 20px', borderTop: '1px solid #0b0e1b', backgroundColor: '#0d0e10' },
    txt2: { color: '#f0b232', fontSize: '1.2em' },
    txt: { margin: 0, color: 'white' },
};

const CryptoStoreModal = ({ onClose, fetchWithAuth, apiBaseUrl }) => {
    const [error, setError] = useState(null);
    const { overlayProps, dialogProps } = useModalA11y({ onClose, label: 'Crypto Store' });
    const store = useCryptoStore({ fetchWithAuth, apiBaseUrl, onClose });
    const { t } = useTranslation();

    return (
        <div style={styles.overlay} {...overlayProps}>
            <div style={styles.modal} {...dialogProps}>
                <div style={styles.header}>
                    <div className="flex-align-10">
                        <FaCoins color="#f0b232" size={24} />
                        <h2 style={S.txt}>{t('store.title', 'Pawscord Store')}</h2>
                    </div>
                    <button aria-label="Close" onClick={onClose} style={styles.closeBtn}><FaTimes /></button>
                </div>

                <div style={styles.balanceBar}>
                    <div className="flex-align-8">
                        <span>{t('store.currentBalance', 'Current Balance')}:</span>
                        <strong style={S.txt2}>{store.balance} Coin</strong>
                        <button
                            aria-label="store handle Daily Claim" onClick={store.handleDailyClaim} style={styles.dailyBtn} disabled={store.loading}>
                            ≡ƒÄü +10
                        </button>
                    </div>
                </div>

                <div style={styles.tabs}>
                    <button
                        aria-label={t('store.shop', 'Store')} style={store.activeTab === 'store' ? styles.activeTab : styles.tab} onClick={() => store.setActiveTab('store')}><FaShoppingBag /> {t('store.shop', 'Store')}</button>
                    <button
                        aria-label={t('store.buyPawsCoin', 'Buy PawsCoin')} style={store.activeTab === 'deposit' ? styles.activeTab : styles.tab} onClick={() => store.setActiveTab('deposit')}><FaBitcoin /> {t('store.buyPawsCoin', 'Buy PawsCoin')}</button>
                    <button
                        aria-label={t('store.myInventory', 'My Inventory')} style={store.activeTab === 'inventory' ? styles.activeTab : styles.tab} onClick={() => store.setActiveTab('inventory')}><FaTshirt /> {t('store.myInventory', 'My Inventory')}</button>
                </div>

                <div style={styles.content}>
                    {store.activeTab === 'store' && <StoreTab storeItems={store.storeItems} loading={store.loading} balance={store.balance} handleBuy={store.handleBuy} />}
                    {store.activeTab === 'inventory' && <InventoryTab inventory={store.inventory} loading={store.loading} handleEquip={store.handleEquip} />}
                    {store.activeTab === 'deposit' && <DepositTab {...store} />}
                </div>

                {store.dailyInfo && (
                    <div style={S.bg}>
                        {store.dailyInfo.claimed ? (
                            <div className="icon-success">
                                ≡ƒÄü {t('store.dailyClaimed', '{{coins}} coins received! New balance: {{balance}}.', { coins: store.dailyInfo.added_coins ?? 0, balance: store.dailyInfo.new_balance ?? store.balance })}
                                {typeof store.dailyInfo.streak !== 'undefined' && <span style={S.txt3}>{t('store.streak', 'Streak')}: {store.dailyInfo.streak}</span>}
                            </div>
                        ) : store.dailyInfo.reason === 'cooldown' ? (
                            <div className="icon-chat">ΓÅ│ {t('store.dailyCooldown', 'Wait for daily reward: {{seconds}}s', { seconds: Math.max(0, store.dailyInfo.remaining_seconds ?? 0) })}</div>
                        ) : (
                            <div style={S.txt4}>ΓÜá∩╕Å {(store.dailyInfo.error || t('store.claimFailed', 'Reward could not be claimed.'))}</div>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

CryptoStoreModal.propTypes = {
    onClose: PropTypes.func,
    fetchWithAuth: PropTypes.func,
    apiBaseUrl: PropTypes.string,
};
export default CryptoStoreModal;

import PropTypes from 'prop-types';
import { FaTimes, FaGift, FaFire, FaCoins, FaCrown, FaCheckCircle } from 'react-icons/fa';
import { useTranslation } from 'react-i18next';
import styles from '../DailyRewardsModal/dailyRewardsStyles';
import useDailyRewards, { calculateTimeUntilNextReward } from '../DailyRewardsModal/useDailyRewards';
import useModalA11y from '../../hooks/useModalA11y';

const ICON_STYLES = {
    claimed: { color: '#23a559', fontSize: '48px' },
    streak: { fontSize: '48px', color: '#f23f42' },
    header: { fontSize: '24px', color: '#23a559' },
};

const getRewardIcon = (type) => {
    switch (type) {
        case 'coins':
            return <FaCoins className="icon-warning" />;
        case 'premium':
            return <FaCrown className="icon-danger" />;
        default:
            return <FaGift className="icon-primary" />;
    }
};

const DailyRewardsModal = ({ fetchWithAuth, apiBaseUrl, onClose }) => {
    const { t } = useTranslation();
    const { overlayProps, dialogProps } = useModalA11y({ onClose, label: 'Daily Rewards' });
    const { rewards, streak, canClaim, loading, claiming, lastClaimed, nextReward, handleClaim } = useDailyRewards({ fetchWithAuth, apiBaseUrl });
    const cycleIndex = streak % 7;

    return (
        <div style={styles.overlay} {...overlayProps}>
            <div style={styles.modal} {...dialogProps}>
                <div style={styles.header}>
                    <div style={styles.headerLeft}><FaGift style={ICON_STYLES.header} /><h2 className="m0-fs20">Daily Rewards</h2></div>
                    <button aria-label="Close" onClick={onClose} style={styles.closeBtn}><FaTimes /></button>
                </div>

                <div style={styles.content}>
                    {loading ? <div style={styles.loading}>{t('common.loading')}</div> : (
                        <>
                            <div style={styles.streakCard}>
                                <FaFire style={ICON_STYLES.streak} />
                                <div style={styles.streakInfo}><div style={styles.streakNumber}>{streak}</div><div style={styles.streakLabel}>Day Streak</div></div>
                            </div>

                            {canClaim && nextReward && (
                                <div style={styles.claimSection}>
                                    <h3 style={styles.sectionTitle}>Today's Reward</h3>
                                    <div style={styles.currentRewardCard}>
                                        <div style={styles.rewardIcon}>{getRewardIcon(nextReward.type)}</div>
                                        <div style={styles.rewardDetails}><div style={styles.rewardAmount}>{nextReward.amount} {nextReward.type}</div><div style={styles.rewardDescription}>{nextReward.description}</div></div>
                                    </div>
                                    <button
                                        aria-label="handle Claim"
                                        onClick={handleClaim}
                                        disabled={claiming}
                                        style={styles.claimBtn}>{claiming ? 'Claiming...' : 'Claim Reward ≡ƒÄü'}</button>
                                </div>
                            )}

                            {!canClaim && lastClaimed && (
                                <div style={styles.alreadyClaimed}>
                                    <FaCheckCircle style={ICON_STYLES.claimed} /><h3>Already Claimed!</h3><p>Come back tomorrow for your next reward</p>
                                    <div style={styles.nextRewardTime}>Next reward in: {calculateTimeUntilNextReward(lastClaimed)}</div>
                                </div>
                            )}

                            <div style={styles.calendarSection}>
                                <h3 style={styles.sectionTitle}>7-Day Reward Cycle</h3>
                                <div style={styles.calendar}>
                                    {rewards.map((reward, idx) => {
                                        const isToday = idx === cycleIndex;
                                        const isClaimed = idx < cycleIndex;
                                        const calendarDayStyle = {
                                            ...styles.calendarDay,
                                            ...(isToday ? styles.calendarDayActive : {}),
                                            ...(isClaimed ? styles.calendarDayClaimed : {}),
                                        };

                                        return (
                                            <div key={`item-${idx}`} style={calendarDayStyle}>
                                                <div style={styles.dayNumber}>Day {idx + 1}</div>
                                                <div style={styles.dayIcon}>{getRewardIcon(reward.type)}</div>
                                                <div style={styles.dayReward}>{reward.amount}</div>
                                                {isClaimed && <div style={styles.claimedBadge}><FaCheckCircle /></div>}
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>

                            <div style={styles.info}>
                                <p style={styles.infoText}>≡ƒôà Log in every day to maintain your streak and earn rewards!</p>
                                <p style={styles.infoText}>≡ƒöÑ Missing a day will reset your streak to 0</p>
                            </div>
                        </>
                    )}
                </div>
            </div>
        </div>
    );
};

DailyRewardsModal.propTypes = {
    fetchWithAuth: PropTypes.func,
    apiBaseUrl: PropTypes.string,
    onClose: PropTypes.func,
};

export default DailyRewardsModal;

import { useState, useEffect } from 'react';
import PropTypes from 'prop-types';
import './EconomySystemPanel.css';
import { FaCoins, FaPaperPlane, FaHistory, FaWallet, FaArrowUp, FaArrowDown } from 'react-icons/fa';
import logger from '../../utils/logger';

function EconomySystemPanel({ apiBaseUrl, fetchWithAuth }) {
  const [balance, setBalance] = useState(0);
  const [history, setHistory] = useState([]);
  const [recipient, setRecipient] = useState('');
  const [amount, setAmount] = useState('');
  const [note, setNote] = useState('');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');

  useEffect(() => {
    loadBalance();
    loadHistory();
  }, []);

  const loadBalance = async () => {
    try {
      const response = await fetchWithAuth(`${apiBaseUrl}/economy/balance/`);
      if (response.ok) {
        const data = await response.json();
        setBalance(data.balance || 0);
      }
    } catch (err) {
      logger.error('Error loading balance:', err);
    }
  };

  const loadHistory = async () => {
    setLoading(true);
    try {
      const response = await fetchWithAuth(`${apiBaseUrl}/economy/history/`);
      if (response.ok) {
        const data = await response.json();
        setHistory(data.transactions || []);
      }
    } catch (err) {
      logger.error('Error loading history:', err);
    } finally {
      setLoading(false);
    }
  };

  const transferCoins = async () => {
    if (!recipient.trim()) {
      setMessage('Γ¥î Please enter recipient username');
      return;
    }

    if (!amount || parseFloat(amount) <= 0) {
      setMessage('Γ¥î Please enter valid amount');
      return;
    }

    if (parseFloat(amount) > balance) {
      setMessage('Γ¥î Insufficient balance');
      return;
    }

    setLoading(true);
    try {
      const response = await fetchWithAuth(`${apiBaseUrl}/economy/transfer/`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          to_username: recipient,
          amount: parseFloat(amount),
          note: note || null
        })
      });

      if (response.ok) {
        const data = await response.json();
        setMessage(`Γ£à Sent ${amount} coins to ${recipient}!`);
        setRecipient('');
        setAmount('');
        setNote('');
        loadBalance();
        loadHistory();
      } else {
        const data = await response.json();
        setMessage(`Γ¥î ${data.error || 'Transfer failed'}`);
      }
    } catch (err) {
      setMessage('Γ¥î Network error: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const formatCoins = (value) => {
    return new Intl.NumberFormat('en-US').format(value);
  };

  return (
    <div className="economy-system-panel">
      <div className="economy-header">
        <h2><FaCoins /> Economy System</h2>
      </div>

      {message && <div className="economy-message">{message}</div>}

      <div className="balance-section">
        <div className="balance-card">
          <FaWallet className="balance-icon" />
          <div className="balance-info">
            <div className="balance-label">Your Balance</div>
            <div className="balance-amount">
              <FaCoins className="coin-icon" />
              {formatCoins(balance)}
            </div>
          </div>
        </div>
      </div>

      <div className="transfer-section">
        <h3><FaPaperPlane /> Send Coins</h3>
        <div className="transfer-form">
          <div className="form-group">
            <label>Recipient Username:</label>
            <input
              type="text"
              placeholder="Enter username..."
              value={recipient}
              onChange={(e) => setRecipient(e.target.value)}
              className="form-input"
            />
          </div>
          <div className="form-group">
            <label>Amount:</label>
            <div className="amount-input-wrapper">
              <FaCoins className="input-coin-icon" />
              <input
                type="number"
                step="1"
                min="1"
                max={balance}
                placeholder="0"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
                className="form-input amount-input"
              />
            </div>
            <div className="balance-hint">Available: {formatCoins(balance)} coins</div>
          </div>
          <div className="form-group">
            <label>Note (optional):</label>
            <input
              type="text"
              placeholder="Add a message..."
              value={note}
              onChange={(e) => setNote(e.target.value)}
              className="form-input"
            />
          </div>
          <button
          aria-label="transfer Coins"
            className="transfer-btn"
            onClick={transferCoins}
            disabled={loading || !recipient || !amount}>
            <FaPaperPlane /> Send Coins
          </button>
        </div>
      </div>

      <div className="history-section">
        <h3><FaHistory /> Transaction History</h3>
        {loading && history.length === 0 ? (
          <div className="loading">Loading history...</div>
        ) : history.length === 0 ? (
          <div className="empty-history">
            <FaHistory className="empty-icon" />
            <p>No transactions yet</p>
          </div>
        ) : (
          <div className="history-list">
            {history.map((transaction, idx) => (
              <div key={`item-${idx}`} className={`history-item ${transaction.type}`}>
                <div className="transaction-icon">
                  {transaction.type === 'sent' ? (
                    <FaArrowUp className="icon-sent" />
                  ) : (
                    <FaArrowDown className="icon-received" />
                  )}
                </div>
                <div className="transaction-info">
                  <div className="transaction-user">
                    {transaction.type === 'sent' 
                      ? `To: ${transaction.to_username}`
                      : `From: ${transaction.from_username}`
                    }
                  </div>
                  {transaction.note && (
                    <div className="transaction-note">{transaction.note}</div>
                  )}
                  <div className="transaction-date">
                    {new Date(transaction.created_at).toLocaleString()}
                  </div>
                </div>
                <div className={`transaction-amount ${transaction.type}`}>
                  {transaction.type === 'sent' ? '-' : '+'}
                  <FaCoins className="amount-coin" />
                  {formatCoins(transaction.amount)}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

EconomySystemPanel.propTypes = {
    apiBaseUrl: PropTypes.string,
    fetchWithAuth: PropTypes.func,
};
export default EconomySystemPanel;

