            await fetchWithAuth(`${apiBaseUrl}/inventory/${itemId}/unequip/`, {
                method: 'POST'
            });
            toast.success('Item unequipped');
            fetchInventory();
        } catch (error) {
            toast.error('Failed to unequip item');
        }
    };

    const useItem = async (itemId) => {
        try {
            await fetchWithAuth(`${apiBaseUrl}/inventory/${itemId}/use/`, {
                method: 'POST'
            });
            toast.success('Item used');
            fetchInventory();
        } catch (error) {
            toast.error('Failed to use item');
        }
    };

    return (
        <div style={styles.overlay}>
            <div style={styles.modal}>
                <div style={styles.header}>
                    <div style={styles.headerLeft}>
                        <FaCube className="icon-primary-mr10" />
                        <h2 style={styles.title}>Inventory</h2>
                    </div>
                    <button aria-label="Close" onClick={onClose} style={styles.closeButton}>
                        <FaTimes />
                    </button>
                </div>

                <div style={styles.filterBar}>
                    {itemTypes.map(type => {
                        const Icon = type.icon;
                        return (
                            <button
          aria-label="Action button"
                                key={type.value}
                                onClick={() => setFilter(type.value)}
                                style={filter === type.value ? styles.activeFilter : styles.filterButton}>
                                <Icon className="mr-6" />
                                {type.label}
                            </button>
                        );
                    })}
                </div>

                <div style={styles.content}>
                    {loading ? (
                        <div style={styles.loading}>Loading inventory...</div>
                    ) : inventory.length === 0 ? (
                        <div style={styles.empty}>No items in inventory</div>
                    ) : (
                        <div style={styles.itemsGrid}>
                            {inventory.map((item, idx) => (
                                <div key={`item-${idx}`} style={styles.itemCard}>
                                    {item.image_url && (
                                        <div style={styles.itemImage}>
                                            <img src={item.image_url} alt={item.name} className="img-cover" />
                                        </div>
                                    )}
                                    {item.equipped && (
                                        <div style={styles.equippedBadge}>
                                            <FaCrown className="fs-12" /> Equipped
                                        </div>
                                    )}
                                    <div style={styles.itemInfo}>
                                        <div style={styles.itemName}>{item.name}</div>
                                        {item.rarity && (
                                            <div style={_st1144}>
                                                {item.rarity.toUpperCase()}
                                            </div>
                                        )}
                                        {item.description && (
                                            <div style={styles.itemDescription}>{item.description}</div>
                                        )}
                                        {item.quantity > 1 && (
                                            <div style={styles.itemQuantity}>Quantity: {item.quantity}</div>
                                        )}
                                        <div style={styles.itemActions}>
                                            {item.type === 'cosmetic' && (
                                                <>
                                                    {item.equipped ? (
                                                        <button
          aria-label="Action button" onClick={() => unequipItem(item.id)} style={styles.unequipButton}>
                                                            Unequip
                                                        </button>
                                                    ) : (
                                                        <button
          aria-label="Action button" onClick={() => equipItem(item.id)} style={styles.equipButton}>
                                                            Equip
                                                        </button>
                                                    )}
                                                </>
                                            )}
                                            {item.usable && (
                                                <button
          aria-label="Action button" onClick={() => useItem(item.id)} style={styles.useButton}>
                                                    Use
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

