import PropTypes from 'prop-types';
import { FaTimes, FaCoins, FaCreditCard, FaHistory, FaWallet } from 'react-icons/fa';
import { useTranslation } from 'react-i18next';
import styles from '../PaymentPanel/styles';
import usePayment from '../PaymentPanel/hooks/usePayment';
import BuyCoinsView from '../PaymentPanel/BuyCoinsView';
import TransferView from '../PaymentPanel/TransferView';

const BALANCE_ICON_STYLE = { fontSize: '48px', color: '#f0b232' };

const PaymentPanel = ({ fetchWithAuth, apiBaseUrl, onClose, username }) => {
    const { t } = useTranslation();
    const {
        activeTab,
        setActiveTab,
        balance,
        transactions,
        loading,
        amount,
        setAmount,
        paymentMethod,
        setPaymentMethod,
        transferRecipient,
        setTransferRecipient,
        transferAmount,
        setTransferAmount,
        transferNote,
        setTransferNote,
        handlePurchase,
        handleTransfer,
    } = usePayment(fetchWithAuth, apiBaseUrl);

    return (
        <div style={styles.overlay} onClick={onClose}>
            <div style={styles.modal} onClick={event => event.stopPropagation()}>
                <div style={styles.header}>
                    <div style={styles.headerLeft}>
                        <FaWallet className="text-f0b-24" />
                        <h2 className="m0-fs20">Payment Center</h2>
                    </div>
                    <button aria-label="Close" onClick={onClose} style={styles.closeBtn}><FaTimes /></button>
                </div>

                <div style={styles.tabs}>
                    {[
                        { key: 'balance', icon: <FaCoins />, label: 'Balance' },
                        { key: 'buy', icon: <FaCreditCard />, label: 'Buy Coins' },
                        { key: 'transfer', icon: <FaCoins />, label: 'Transfer' },
                        { key: 'history', icon: <FaHistory />, label: 'History' }
                    ].map(tab => {
                        const tabStyle = { ...styles.tab, ...(activeTab === tab.key ? styles.activeTab : {}) };

                        return (
                            <button
                                aria-label="Switch tab"
                                key={tab.key}
                                onClick={() => setActiveTab(tab.key)}
                                style={tabStyle}>
                                {tab.icon} {tab.label}
                            </button>
                        );
                    })}
                </div>

                <div style={styles.content}>
                    {loading ? (
                        <div style={styles.loading}>{t('common.loading')}</div>
                    ) : activeTab === 'balance' ? (
                        <div style={styles.balanceView}>
                            <div style={styles.balanceCard}>
                                <FaCoins style={BALANCE_ICON_STYLE} />
                                <div style={styles.balanceAmount}>{balance.toLocaleString()}</div>
                                <div style={styles.balanceLabel}>Current Balance</div>
                            </div>
                            <div style={styles.quickActions}>
                                <button
                                    aria-label="Buy Coins"
                                    onClick={() => setActiveTab('buy')}
                                    style={styles.actionBtn}><FaCreditCard /> Buy Coins</button>
                                <button
                                    aria-label="Transfer Coins"
                                    onClick={() => setActiveTab('transfer')}
                                    style={styles.actionBtn}><FaCoins /> Transfer Coins</button>
                            </div>
                        </div>
                    ) : activeTab === 'buy' ? (
                        <BuyCoinsView
                            styles={styles}
                            amount={amount}
                            setAmount={setAmount}
                            paymentMethod={paymentMethod}
                            setPaymentMethod={setPaymentMethod}
                            handlePurchase={handlePurchase}
                        />
                    ) : activeTab === 'transfer' ? (
                        <TransferView
                            styles={styles}
                            balance={balance}
                            transferRecipient={transferRecipient}
                            setTransferRecipient={setTransferRecipient}
                            transferAmount={transferAmount}
                            setTransferAmount={setTransferAmount}
                            transferNote={transferNote}
                            setTransferNote={setTransferNote}
                            handleTransfer={handleTransfer}
                        />
                    ) : (
                        <div style={styles.historyView}>
                            <h3 style={styles.sectionTitle}>Transaction History</h3>
                            {transactions.length === 0 ? (
                                <div style={styles.empty}>No transactions yet</div>
                            ) : (
                                <div style={styles.transactions}>
                                    {transactions.map((tx, idx) => {
                                        const coinIconStyle = { color: tx.type === 'transfer_sent' ? '#f23f42' : '#23a559' };
                                        const txAmountStyle = { ...styles.txAmount, color: tx.amount > 0 ? '#23a559' : '#f23f42' };

                                        return (
                                            <div key={`item-${idx}`} style={styles.transaction}>
                                                <div style={styles.txIcon}>
                                                    {tx.type === 'purchase'
                                                        ? <FaCreditCard className="icon-primary" />
                                                        : <FaCoins style={coinIconStyle} />}
                                                </div>
                                                <div style={styles.txDetails}>
                                                    <div style={styles.txTitle}>{tx.description}</div>
                                                    <div style={styles.txDate}>{new Date(tx.created_at).toLocaleString()}</div>
                                                </div>
                                                <div style={txAmountStyle}>
                                                    {tx.amount > 0 ? '+' : ''}{tx.amount}
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

