import { useState, useEffect } from 'react';
import PropTypes from 'prop-types';
import './PremiumManagementPanel.css';
import { toast } from 'react-toastify';
import { getApiBase } from '../../utils/apiEndpoints';
import confirmDialog from '../../utils/confirmDialog';

import { useTranslation } from 'react-i18next';
import logger from '../../utils/logger';
const PremiumManagementPanel = ({ onClose }) => {
    const { t } = useTranslation();
    const [pricingTiers, setPricingTiers] = useState([]);
    const [currentSubscription, setCurrentSubscription] = useState(null);
    const [loading, setLoading] = useState(true);
    const [selectedTier, setSelectedTier] = useState('classic');
    const [billingCycle, setBillingCycle] = useState('monthly'); // monthly or yearly
    const apiBaseUrl = getApiBase();
    const token = localStorage.getItem('access_token');

    useEffect(() => {
        fetchPricingTiers();
        fetchCurrentSubscription();
    }, []);

    const fetchPricingTiers = async () => {
        try {
            const response = await fetch(`${apiBaseUrl}/nitro/pricing/`, {
                headers: {
                    'Authorization': `Bearer ${token}`
                }
            });
            const data = await response.json();
            setPricingTiers(data.tiers || []);
        } catch (error) {
            logger.error('Error fetching pricing:', error);
            toast.error('Γ¥î Pricing info could not be loaded');
        }
    };

    const fetchCurrentSubscription = async () => {
        try {
            const response = await fetch(`${apiBaseUrl}/nitro/my-subscription/`, {
                headers: {
                    'Authorization': `Bearer ${token}`
                }
            });
            const data = await response.json();
            setCurrentSubscription(data.subscription || null);
        } catch (error) {
            logger.error('Error fetching subscription:', error);
        } finally {
            setLoading(false);
        }
    };

    const subscribe = async () => {
        try {
            const response = await fetch(`${apiBaseUrl}/nitro/subscribe/`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    tier: selectedTier,
                    billing_cycle: billingCycle,
                    payment_method: 'stripe' // or 'test' for testing
                })
            });

            const data = await response.json();

            if (response.ok) {
                toast.success(t('ui.subscription_successfully_baslatildi'));
                fetchCurrentSubscription();
            } else {
                toast.error(`Γ¥î ${data.error || t('ui.subscription_baslatilamadi')}`);
            }
        } catch (error) {
            logger.error('Error subscribing:', error);
            toast.error(t('ui.subscription_hatasi'));
        }
    };

    const cancelSubscription = async () => {
        if (!await confirmDialog('Are you sure you want to cancel your subscription?')) return;

        try {
            const response = await fetch(`${apiBaseUrl} / nitro / cancel / `, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                }
            });

            const data = await response.json();

            if (response.ok) {
                toast.info('Γä╣∩╕Å Subscription cancel edildi');
                fetchCurrentSubscription();
            } else {
                toast.error(`Γ¥î ${data.error || 'Cancel edilemedi'}`);
            }
        } catch (error) {
            logger.error('Error canceling:', error);
            toast.error(t('ui.cancel_hatasi'));
        }
    };

    const upgradeSubscription = async (newTier) => {
        try {
            const response = await fetch(`${apiBaseUrl} / nitro / upgrade / `, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    new_tier: newTier
                })
            });

            const data = await response.json();

            if (response.ok) {
                toast.success(t('ui.subscription_yukseltildi'));
                fetchCurrentSubscription();
            } else {
                toast.error(`Γ¥î ${data.error || 'Could not be upgraded'}`);
            }
        } catch (error) {
            logger.error('Error upgrading:', error);
            toast.error(t('ui.yukseltme_hatasi'));
        }
    };

    const getTierColor = (tier) => {
        const colors = {
            'basic': '#3b82f6',
            'classic': '#5865f2',
            'elite': '#f59e0b'
        };
        return colors[tier] || colors.classic;
    };

    const getTierIcon = (tier) => {
        const icons = {
            'basic': '≡ƒîƒ',
            'classic': '≡ƒÆÄ',
            'elite': '≡ƒææ'
        };
        return icons[tier] || icons.classic;
    };

    const getFeatureIcon = (featureName) => {
        const iconMap = {
            'upload_limit_mb': '≡ƒôñ',
            'video_quality': '≡ƒÄÑ',
            'emoji_slots': '≡ƒÿÇ',
            'custom_tag': '≡ƒÅ╖∩╕Å',
            'animated_avatar': '≡ƒÄ¡',
            'server_boosts': '≡ƒÜÇ',
            'custom_profiles': 'Γ£¿',
            'hd_video': '≡ƒô║',
            'screen_share_quality': '≡ƒûÑ∩╕Å',
            'profile_banner': '≡ƒÄ¿',
            'custom_discriminator': '#∩╕ÅΓâú',
            'badge': '≡ƒÅå',
            'early_access': '≡ƒöô',
            'priority_support': '≡ƒÆ¼'
        };
        return iconMap[featureName] || 'Γ£ô';
    };

    const formatFeatureValue = (key, value) => {
        if (typeof value === 'boolean') return value ? 'Evet' : t('common.no');
        if (key === 'upload_limit_mb') return `${value} MB`;
        if (key.includes('quality')) return value;
        return value;
    };

    if (loading) {
        return (
            <div className="premium-overlay">
                <div className="premium-panel">
                    <div className="loading-state">
                        <div className="spinner"></div>
                        <span>{t("common.loading")}</span>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="premium-overlay" onClick={onClose}>
            <div className="premium-panel" onClick={(e) => e.stopPropagation()}>
                {/* Header */}
                <div className="premium-header">
                    <h2>≡ƒÆÄ Pawscord Premium</h2>
                    <button aria-label="Close" className="close-btn" onClick={onClose}>Γ£ò</button>
                </div>

                {/* Current Subscription */}
                {currentSubscription ? (
                    <div className="current-subscription">
                        <div className="subscription-header">
                            <span className="subscription-icon">{getTierIcon(currentSubscription.tier)}</span>
                            <div className="subscription-info">
                                <h3>{currentSubscription.tier_name || currentSubscription.tier.toUpperCase()}</h3>
                                <span className="subscription-status">
                                    {currentSubscription.is_active ? 'Γ£ô Active' : t('ui.stopulmus')}
                                </span>
                            </div>
                            <div className="subscription-actions">
                                <button
                                    aria-label="cancel Subscription" className="cancel-btn" onClick={cancelSubscription}>
                                    Cancel Et
                                </button>
                            </div>
                        </div>
                        <div className="subscription-details">
                            <div className="detail-item">
                                <span className="detail-label">Ba┼ƒlang─▒├º:</span>
                                <span className="detail-value">
                                    {new Date(currentSubscription.start_date).toLocaleDateString('tr-TR')}
                                </span>
                            </div>
                            <div className="detail-item">
                                <span className="detail-label">Biti┼ƒ:</span>
                                <span className="detail-value">
                                    {new Date(currentSubscription.end_date).toLocaleDateString('tr-TR')}
                                </span>
                            </div>
                            <div className="detail-item">
                                <span className="detail-label">Auto Refreshme:</span>
                                <span className="detail-value">
                                    {currentSubscription.auto_renew ? 'Open' : 'Closed'}
                                </span>
                            </div>
                        </div>
                    </div>
                ) : (
                    <div className="no-subscription">
                        <div className="no-subscription-icon">≡ƒÆÄ</div>
                        <h3>Premium Membership Yok</h3>
                        <p>Premium ├╢zelliklerden yararlanmak for a┼ƒa─ƒ─▒daki planlardan birini se├ºin</p>
                    </div>
                )}

                {/* Billing Cycle Toggle */}
                <div className="billing-toggle">
                    <button
                        aria-label="Action button"
                        className={`billing - option ${billingCycle === 'monthly' ? 'active' : ''} `}
                        onClick={() => setBillingCycle('monthly')}>
                        Monthly
                    </button>
                    <button
                        aria-label="Action button"
                        className={`billing - option ${billingCycle === 'yearly' ? 'active' : ''} `}
                        onClick={() => setBillingCycle('yearly')}>
