                    </button>
                </div>

                {/* Pricing Tiers */}
                <div className="pricing-tiers">
                    {Object.keys(pricingTiers).map(tierKey => {
                        const tier = pricingTiers[tierKey];
                        const isCurrentTier = currentSubscription?.tier === tierKey;
                        const price = billingCycle === 'yearly' ? tier.price_yearly : tier.price_monthly;
                        const tierCardBorderStyle = { borderColor: getTierColor(tierKey) };
                        const tierHeaderBgStyle = { background: `linear - gradient(135deg, ${getTierColor(tierKey)}, ${getTierColor(tierKey)}99)` };
                        const tierActionBtnStyle = { background: `linear - gradient(135deg, ${getTierColor(tierKey)}, ${getTierColor(tierKey)}dd)` };

                        return (
                            <div
                                key={tierKey}
                                className={`tier - card ${selectedTier === tierKey ? 'selected' : ''} ${isCurrentTier ? 'current' : ''} `}
                                style={tierCardBorderStyle}
                                onClick={() => !isCurrentTier && setSelectedTier(tierKey)}>
                                <div className="tier-header" style={tierHeaderBgStyle}>
                                    <span className="tier-icon">{getTierIcon(tierKey)}</span>
                                    <h3>{tier.name}</h3>
                                    {isCurrentTier && <span className="current-badge">Mevcut Plan</span>}
                                </div>

                                <div className="tier-price">
                                    <span className="price-amount">${price}</span>
                                    <span className="price-period">/{billingCycle === 'yearly' ? 'year' : 'month'}</span>
                                </div>

                                <div className="tier-features">
                                    {Object.entries(tier.features).map(([key, value]) => (
                                        <div key={key} className="feature-item">
