                            <span style={UI_STYLES.balanceText}>
                                {(premiumStatus?.coins || 0).toLocaleString()}
                            </span>
                        </div>
                        <button aria-label="Close" onClick={onClose} style={styles.closeButton}>
                            <FaTimes />
                        </button>
                    </div>
                </div>

                <div style={styles.tabs}>
                    <button aria-label="Switch tab" onClick={() => setActiveTab('premium')} style={tabStyles.premium}>
                        <FaCrown /> Premium
                    </button>
                    <button aria-label="Switch tab" onClick={() => setActiveTab('store')} style={tabStyles.store}>
                        <FaShoppingCart /> Magaza
                    </button>
                    <button aria-label="Switch tab" onClick={() => setActiveTab('boost')} style={tabStyles.boost}>
                        <FaRocket /> Server Boost
                    </button>
                </div>

                <div style={styles.content}>
                    {activeTab === 'premium' && <PremiumTab styles={styles} handlePurchase={handlePurchase} />}
                    {activeTab === 'store' && (
                        <StoreTab
                            styles={styles}
                            storeItems={storeItems}
                            userInventory={userInventory}
                            handleBuyItem={handleBuyItem}
                            loading={loading}
                        />
                    )}
                    {activeTab === 'boost' && (
                        <BoostTab
                            styles={styles}
                            loading={loading}
                            setLoading={setLoading}
                            token={token}
                            API_BASE_URL={API_BASE_URL}
                        />
                    )}
                </div>
            </div>
        </div>
    );
};

