import React from 'react';
import PropTypes from 'prop-types';
import { FaTimes, FaShoppingCart, FaCoins, FaFire, FaCrown, FaPalette, FaMedal, FaGift } from 'react-icons/fa';
import useStoreAPI from '../StoreModal/useStoreAPI';
import ItemDetailModal from '../StoreModal/ItemDetailModal';
import s, { CATEGORIES } from '../StoreModal/storeModalStyles';
import useModalA11y from '../../hooks/useModalA11y';

const ITEM_ICON_STYLE = { fontSize: '48px', color: '#949ba4' };
const _st1145 = {};
const ICON_MAP = { FaShoppingCart, FaPalette, FaMedal, FaFire, FaCrown };

const ItemCard = ({ item, onClick }) => (
    <div style={s.itemCard} onClick={() => onClick(item)}>
        {item.image ? <img src={item.image} alt={item.name} style={s.itemImage} />
            : <div style={s.itemPlaceholder}><FaGift style={ITEM_ICON_STYLE} /></div>}
        <div style={s.itemInfo}>
            <div style={_st1145}>{item.name}</div>
            <div style={s.itemPrice}><FaCoins className="icon-warning" />{item.price.toLocaleString()}</div>
        </div>
        {item.limited && <div style={s.limitedBadge}>LIMITED</div>}
    </div>
);

const StoreModal = ({ fetchWithAuth, apiBaseUrl, onClose, username }) => {
    const { overlayProps, dialogProps } = useModalA11y({ onClose, label: 'Store' });
    const store = useStoreAPI({ fetchWithAuth, apiBaseUrl });

    return (
        <div style={s.overlay} {...overlayProps}>
            <div style={s.modal} {...dialogProps}>
                <div style={s.header}>
                    <div style={s.headerLeft}>
                        <FaShoppingCart className="icon-primary-24" />
                        <h2 className="m0-fs20">Item Store</h2>
                    </div>
                    <div style={s.headerRight}>
                        <div style={s.balance}><FaCoins className="icon-warning" /><span>{store.balance.toLocaleString()}</span></div>
                        <button aria-label="Close" onClick={onClose} style={s.closeBtn}><FaTimes /></button>
                    </div>
                </div>

                <div style={s.categories}>
                    {CATEGORIES.map(cat => {
                        const Icon = ICON_MAP[cat.icon];
                        const categoryButtonStyle = { ...s.categoryBtn, ...(store.selectedCategory === cat.id ? s.activeCategoryBtn : {}) };

                        return (
                            <button
                                aria-label="Action button"
                                key={cat.id}
                                onClick={() => store.setSelectedCategory(cat.id)}
                                style={categoryButtonStyle}>
                                <Icon /><span>{cat.name}</span>
                            </button>
                        );
                    })}
                </div>

                <div style={s.content}>
                    {store.loading ? <div style={s.loading}>Loading store...</div> : (
                        <>
                            {store.selectedCategory === 'all' && store.featuredItems.length > 0 && (
                                <div style={s.section}>
                                    <h3 style={s.sectionTitle}><FaFire className="icon-danger" /> Featured Items</h3>
                                    <div style={s.itemsGrid}>
                                        {store.featuredItems.map(item => <ItemCard key={item.id} item={item} onClick={store.setSelectedItem} />)}
                                    </div>
                                </div>
                            )}
                            <div style={s.section}>
                                <h3 style={s.sectionTitle}>{CATEGORIES.find(c => c.id === store.selectedCategory)?.name || 'All Items'}</h3>
                                {store.filteredItems.length === 0 ? <div style={s.empty}>No items in this category</div> : (
                                    <div style={s.itemsGrid}>
                                        {store.filteredItems.map(item => <ItemCard key={item.id} item={item} onClick={store.setSelectedItem} />)}
                                    </div>
                                )}
                            </div>
                        </>
                    )}
                </div>

                <ItemDetailModal
                    item={store.selectedItem}
                    balance={store.balance}
                    onClose={() => store.setSelectedItem(null)}
                    onPurchase={store.handlePurchase}
                />
            </div>
        </div>
    );
};

StoreModal.propTypes = {
    fetchWithAuth: PropTypes.func,
    apiBaseUrl: PropTypes.string,
    onClose: PropTypes.func,
    username: PropTypes.string,
};

ItemCard.propTypes = {
    item: PropTypes.object,
    onClick: PropTypes.func,
};

export default StoreModal;

